import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { toast, ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';
import Header from './Header';
import { rfidService } from '../services/rfidService';

const API_ENDPOINTS = [
  {
    name: 'Save RFID Transaction Details',
    endpoint: 'SaveRFIDTransactionDetails',
    method: 'POST',
    description: 'Save new RFID transaction details with complete product information including weights, pricing, and status.',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: false,
    icon: 'fas fa-save text-white',
    highlight: 'primary',
    gradient: 'linear-gradient(135deg, #8E2DE2, #4A00E0)',
    sampleBody: {
      client_code: "LS000123",
      RFIDNumber: "CZ3506",
      Itemcode: "SAU124",
      category_id: "Gold",
      product_id: "Tops",
      design_id: "Fancy Top",
      purity_id: "22CT",
      grosswt: "20.800",
      stonewt: "0.500",
      diamondheight: "0.250",
      netwt: "19.250",
      box_details: "Box A",
      size: 0,
      stoneamount: "20",
      diamondAmount: "20",
      HallmarkAmount: "35",
      MakingPerGram: "10",
      MakingPercentage: "5",
      MakingFixedAmt: "37",
      MRP: "5000",
      imageurl: "",
      status: "ApiActive"
    }
  },
  {
    name: 'Update RFID Transaction Details',
    endpoint: 'UpdateRFIDTransactionDetails',
    method: 'POST',
    description: 'Update the status of RFID items (e.g., mark as Sold).',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: true,
    icon: 'fas fa-edit text-white',
    highlight: 'info',
    gradient: 'linear-gradient(135deg, #4A00E0, #8E2DE2)',
    sampleBody: {
      client_code: "LS000186",
      RFIDNumber: "CZ3581",
      status: "Sold"
    }
  },
  {
    name: 'Get RFID Transaction Details',
    endpoint: 'GetRFIDTransactionDetails',
    method: 'POST',
    description: 'Retrieve all active RFID transactions for a client.',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: true,
    icon: 'fas fa-search text-white',
    highlight: 'primary',
    gradient: 'linear-gradient(135deg, #06beb6, #48b1bf)',
    sampleBody: {
      client_code: "LS000186",
      status: "Active"
    }
  },
  {
    name: 'Delete Labelled Stock Items',
    endpoint: 'DeleteLabelledStockItems',
    method: 'POST',
    description: 'Remove specified items from labelled stock inventory.',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: true,
    icon: 'fas fa-trash text-white',
    highlight: 'danger',
    gradient: 'linear-gradient(135deg, #d60000, #ff0000)',
    sampleBody: {
      ClientCode: "LS000186",
      ItemCodes: ["ITEM001", "ITEM002"]
    }
  }
];

const Dashboard = () => {
  const navigate = useNavigate();
  const [userInfo, setUserInfo] = useState({});
  const [selectedEndpoint, setSelectedEndpoint] = useState(null);
  const [response, setResponse] = useState(null);
  const [loading, setLoading] = useState(false);
  const [requestBody, setRequestBody] = useState({});
  const [clientError, setClientError] = useState('');

  useEffect(() => {
    const userInfo = JSON.parse(localStorage.getItem('userInfo')) || {};
    setUserInfo(userInfo);
  }, []);

  const handleEndpointClick = (endpoint) => {
    setSelectedEndpoint(endpoint);
    setResponse(null);
    setRequestBody(endpoint.sampleBody);
    setClientError('');
  };

  const validateClientCode = (body) => {
    if (body.client_code !== userInfo.ClientCode && body.ClientCode !== userInfo.ClientCode) {
      setClientError('Please enter your valid client code');
      return false;
    }
    setClientError('');
    return true;
  };

  const handleRequestBodyChange = (value) => {
    try {
      const parsedBody = JSON.parse(value);
      setRequestBody(parsedBody);
    } catch (error) {
      console.error('Invalid JSON:', error);
    }
  };

  const handleTestEndpoint = async () => {
    if (!selectedEndpoint) return;
    if (!validateClientCode(requestBody)) return;

    setLoading(true);
    try {
      let result;
      const clientCode = userInfo.ClientCode;

      switch (selectedEndpoint.endpoint) {
        case 'GetRFIDTransactionDetails':
          result = await rfidService.getRFIDTransactions(clientCode);
          break;
        case 'UpdateRFIDTransactionDetails':
          result = await rfidService.updateRFIDTransaction(requestBody);
          break;
        case 'DeleteLabelledStockItems':
          result = await rfidService.deleteLabelledStock(clientCode, requestBody.ItemCodes);
          break;
        case 'SaveRFIDTransactionDetails':
          result = await rfidService.saveRFIDTransaction(requestBody);
          break;
        default:
          break;
      }

      setResponse(result);
      toast.success('API call successful!');
    } catch (error) {
      console.error('API Error:', error);
      setResponse(error.response?.data || error.message);
      toast.error('API call failed. Please check console for details.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ minHeight: '100vh', background: 'linear-gradient(135deg, #f8f9fa 0%, #e9ecef 100%)' }}>
      <Header userInfo={userInfo} />
      <div className="container-fluid py-4">
        <div className="row">
          <div className="col-md-4">
            <div className="card shadow-lg border-0" style={{ borderRadius: '15px', background: 'linear-gradient(135deg, #ffffff 0%, #f8f9fa 100%)' }}>
              <div className="card-body p-4">
                <h4 className="mb-4 fw-bold text-primary">API Endpoints</h4>
                <div className="list-group">
                  {API_ENDPOINTS.map((endpoint) => (
                    <button
                      key={endpoint.endpoint}
                      className={`list-group-item list-group-item-action border-0 mb-3 ${selectedEndpoint?.endpoint === endpoint.endpoint ? 'active' : ''}`}
                      onClick={() => handleEndpointClick(endpoint)}
                      style={{
                        borderRadius: '10px',
                        background: selectedEndpoint?.endpoint === endpoint.endpoint ? endpoint.gradient : 'white',
                        transition: 'all 0.3s ease',
                        transform: selectedEndpoint?.endpoint === endpoint.endpoint ? 'scale(1.02)' : 'scale(1)',
                        boxShadow: selectedEndpoint?.endpoint === endpoint.endpoint ? '0 8px 16px rgba(0,0,0,0.1)' : '0 4px 6px rgba(0,0,0,0.05)'
                      }}
                    >
                      <div className="d-flex align-items-center">
                        <div className="me-3" style={{
                          width: '40px',
                          height: '40px',
                          borderRadius: '10px',
                          background: endpoint.gradient,
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center'
                        }}>
                          <i className={endpoint.icon}></i>
                        </div>
                        <div>
                          <h6 className={`mb-1 ${selectedEndpoint?.endpoint === endpoint.endpoint ? 'text-white' : 'text-dark'}`}>
                            {endpoint.name}
                          </h6>
                          <small className={selectedEndpoint?.endpoint === endpoint.endpoint ? 'text-white-50' : 'text-muted'}>
                            {endpoint.method} {endpoint.endpoint}
                          </small>
                        </div>
                      </div>
                    </button>
                  ))}
                </div>
              </div>
            </div>
          </div>

          <div className="col-md-8">
            {selectedEndpoint && (
              <div className="card shadow-lg border-0" style={{ borderRadius: '15px', background: 'linear-gradient(135deg, #ffffff 0%, #f8f9fa 100%)' }}>
                <div className="card-body p-4">
                  <h4 className="mb-4 fw-bold" style={{ color: '#333' }}>
                    {selectedEndpoint.name}
                    <span className="badge bg-primary ms-2">{selectedEndpoint.method}</span>
                  </h4>

                  <div className="mb-4">
                    <h6 className="fw-bold mb-3">Description</h6>
                    <p className="text-muted">{selectedEndpoint.description}</p>
                  </div>

                  <div className="mb-4">
                    <h6 className="fw-bold mb-3">Request Body</h6>
                    <div className="position-relative">
                      <textarea
                        className="form-control"
                        style={{
                          height: '200px',
                          fontFamily: 'monospace',
                          fontSize: '14px',
                          backgroundColor: '#f8f9fa',
                          border: '1px solid #dee2e6',
                          borderRadius: '10px'
                        }}
                        value={JSON.stringify(requestBody, null, 2)}
                        onChange={(e) => handleRequestBodyChange(e.target.value)}
                      />
                      {clientError && (
                        <div className="alert alert-danger mt-2">
                          {clientError}
                        </div>
                      )}
                    </div>
                  </div>

                  <button
                    className="btn btn-primary px-4 py-2"
                    onClick={handleTestEndpoint}
                    disabled={loading}
                    style={{
                      background: selectedEndpoint.gradient,
                      border: 'none',
                      borderRadius: '10px',
                      transition: 'all 0.3s ease'
                    }}
                  >
                    {loading ? (
                      <>
                        <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
                        Testing...
                      </>
                    ) : (
                      <>
                        <i className="fas fa-play me-2"></i>
                        Test Endpoint
                      </>
                    )}
                  </button>

                  {response && (
                    <div className="mt-4">
                      <h6 className="fw-bold mb-3">Response</h6>
                      <div className="response-container" style={{ maxHeight: '300px', overflow: 'auto' }}>
                        <pre
                          style={{
                            backgroundColor: '#f8f9fa',
                            padding: '1rem',
                            borderRadius: '10px',
                            fontSize: '14px',
                            margin: 0
                          }}
                        >
                          {JSON.stringify(response, null, 2)}
                        </pre>
                      </div>
                    </div>
                  )}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
      <ToastContainer position="bottom-right" />
    </div>
  );
};

export default Dashboard;
